import React, { useEffect, useRef } from 'react';
import Lottie from 'lottie-web';
import animationData from './assets/Ai.json'; // Adjust path as needed
import logo1 from './assets/apple-logo.svg'; // Adjust path as needed
import logo2 from './assets/android-logo.svg'; // Adjust path as needed
import './Home.css';

const Home = () => {
  const animationContainer = useRef(null);

  useEffect(() => {
    Lottie.loadAnimation({
      container: animationContainer.current,
      renderer: 'svg',
      loop: true,
      autoplay: true,
      animationData: animationData
    });
  }, []);

  return (
    <div className="home-container">
      <h1>Mac Keating Ltd</h1>
      <img src={logo1} alt="Apple Logo" className="logo" />

      <img src={logo2} alt="Android Logo" className="logo" />
      <h2>Providing AI Solutions</h2>

    </div>
  );
};

export default Home;
